/**
 * AdminAvailability — CRUD правил доступности преподавателя + holidays.
 * Работает и для учителя (его собственное расписание), и для админа (любого учителя).
 */

import { useEffect, useState } from 'react'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import {
  fetchMyAvailability, createAvailability, updateAvailability, deleteAvailability,
  fetchHolidays, createHoliday, deleteHoliday, generateSlots,
  type AvailabilityRule, type HolidayDto,
} from '../api/availability'

const DAY_NAMES = ['Воскресенье', 'Понедельник', 'Вторник', 'Среда', 'Четверг', 'Пятница', 'Суббота']

export default function AdminAvailability() {
  const { toast, show } = useToast()

  const [rules, setRules] = useState<AvailabilityRule[]>([])
  const [holidays, setHolidays] = useState<HolidayDto[]>([])
  const [loading, setLoading] = useState(true)

  // New rule form
  const [day, setDay] = useState(1)
  const [start, setStart] = useState('15:00')
  const [end, setEnd] = useState('21:00')
  const [duration, setDuration] = useState(60)

  // New holiday
  const [hDate, setHDate] = useState('')
  const [hLabel, setHLabel] = useState('')
  const [hRecurring, setHRecurring] = useState(false)

  const [generating, setGenerating] = useState(false)
  const [genFrom, setGenFrom] = useState(() => new Date().toISOString().slice(0, 10))
  const [genTo, setGenTo] = useState(() => {
    const d = new Date(); d.setDate(d.getDate() + 28); return d.toISOString().slice(0, 10)
  })

  function refresh() {
    setLoading(true)
    Promise.allSettled([fetchMyAvailability(), fetchHolidays()])
      .then(([r, h]) => {
        if (r.status === 'fulfilled') setRules(r.value); else show('Правила не загрузились', 'error')
        if (h.status === 'fulfilled') setHolidays(h.value)
      })
      .finally(() => setLoading(false))
  }

  useEffect(refresh, [])

  async function handleAddRule() {
    if (!start || !end || start >= end) { show('Неверный интервал', 'error'); return }
    try {
      await createAvailability({ dayOfWeek: day, startTime: start, endTime: end, slotDurationMin: duration })
      show('Правило добавлено', 'success')
      refresh()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  async function handleToggleRule(id: string, isActive: boolean) {
    try {
      await updateAvailability(id, { isActive: !isActive })
      refresh()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  async function handleDeleteRule(id: string) {
    if (!confirm('Удалить правило?')) return
    try {
      await deleteAvailability(id)
      refresh()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  async function handleAddHoliday() {
    if (!hDate || !hLabel.trim()) { show('Заполни дату и название', 'error'); return }
    try {
      await createHoliday(hDate, hLabel.trim(), null, hRecurring)
      setHDate(''); setHLabel(''); setHRecurring(false)
      show('Праздник добавлен', 'success')
      refresh()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  async function handleDeleteHoliday(id: string) {
    if (!confirm('Удалить?')) return
    try { await deleteHoliday(id); refresh() }
    catch (e) { show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error') }
  }

  async function handleGenerate() {
    setGenerating(true)
    try {
      const res = await generateSlots(genFrom, genTo)
      show(`Создано ${res.created}, пропущено ${res.skipped}`, 'success')
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setGenerating(false)
    }
  }

  return (
    <PlatformShell activeKey="teacher">
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>⏰</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Расписание</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Доступность и каникулы</h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 900, margin: '0 auto', padding: '28px 16px', display: 'flex', flexDirection: 'column', gap: 24 }}>

        {/* Правила доступности */}
        <section className="kb-card" style={{ padding: 24 }}>
          <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800 }}>Правила доступности (еженедельно)</h2>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(120px, 1fr))', gap: 10, marginBottom: 12, alignItems: 'end' }}>
            <div><label style={lbl}>День</label>
              <select style={inp} value={day} onChange={(e) => setDay(Number(e.target.value))}>
                {DAY_NAMES.map((n, i) => <option key={i} value={i}>{n}</option>)}
              </select>
            </div>
            <div><label style={lbl}>Начало</label><input style={inp} type="time" value={start} onChange={(e) => setStart(e.target.value)} /></div>
            <div><label style={lbl}>Конец</label><input style={inp} type="time" value={end} onChange={(e) => setEnd(e.target.value)} /></div>
            <div><label style={lbl}>Длит. слота</label>
              <select style={inp} value={duration} onChange={(e) => setDuration(Number(e.target.value))}>
                <option value={45}>45 мин</option>
                <option value={60}>60 мин</option>
                <option value={90}>90 мин</option>
              </select>
            </div>
            <button className="kb-btn" style={{ background: 'var(--violet, #6b5ce7)', color: '#fff' }} onClick={() => void handleAddRule()}>+ Добавить</button>
          </div>

          {loading ? (
            <div style={{ padding: 16, textAlign: 'center', color: 'var(--ink-soft)' }}>Загрузка…</div>
          ) : rules.length === 0 ? (
            <div style={{ padding: 16, textAlign: 'center', color: 'var(--ink-soft)', fontSize: 13 }}>Правил пока нет</div>
          ) : (
            <table style={{ width: '100%', fontSize: 13, borderCollapse: 'collapse' }}>
              <thead><tr style={{ textAlign: 'left', background: 'var(--paper-2, #f9f8ff)' }}>
                <th style={{ padding: 8 }}>День</th>
                <th style={{ padding: 8 }}>Время</th>
                <th style={{ padding: 8 }}>Слот</th>
                <th style={{ padding: 8 }}>Активно</th>
                <th style={{ padding: 8 }}></th>
              </tr></thead>
              <tbody>
                {rules.map((r) => (
                  <tr key={r.id} style={{ borderTop: '1px solid var(--paper-3)', opacity: r.isActive ? 1 : 0.5 }}>
                    <td style={{ padding: 8 }}>{DAY_NAMES[r.dayOfWeek]}</td>
                    <td style={{ padding: 8, fontFamily: 'monospace' }}>{r.startTime}–{r.endTime}</td>
                    <td style={{ padding: 8 }}>{r.slotDurationMin} мин</td>
                    <td style={{ padding: 8 }}>
                      <label style={{ display: 'inline-flex', gap: 4, alignItems: 'center', cursor: 'pointer' }}>
                        <input type="checkbox" checked={r.isActive} onChange={() => void handleToggleRule(r.id, r.isActive)} />
                        {r.isActive ? 'да' : 'нет'}
                      </label>
                    </td>
                    <td style={{ padding: 8, textAlign: 'right' }}>
                      <button className="kb-btn" style={{ fontSize: 11, padding: '4px 10px', background: '#dc2626', color: '#fff' }} onClick={() => void handleDeleteRule(r.id)}>×</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </section>

        {/* Праздники */}
        <section className="kb-card" style={{ padding: 24 }}>
          <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800 }}>Праздники / выходные</h2>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: 10, alignItems: 'end', marginBottom: 12 }}>
            <div><label style={lbl}>Дата</label><input style={inp} type="date" value={hDate} onChange={(e) => setHDate(e.target.value)} /></div>
            <div><label style={lbl}>Название</label><input style={inp} value={hLabel} onChange={(e) => setHLabel(e.target.value)} placeholder="Новый год" /></div>
            <div><label style={lbl}>Каждый год</label>
              <label style={{ display: 'flex', alignItems: 'center', height: 38, gap: 6 }}>
                <input type="checkbox" checked={hRecurring} onChange={(e) => setHRecurring(e.target.checked)} />
                ежегодный
              </label>
            </div>
            <button className="kb-btn" style={{ background: 'var(--violet)', color: '#fff' }} onClick={() => void handleAddHoliday()}>+ Добавить</button>
          </div>

          {holidays.length === 0 ? (
            <div style={{ padding: 16, textAlign: 'center', color: 'var(--ink-soft)', fontSize: 13 }}>Нет</div>
          ) : (
            <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'flex', flexDirection: 'column', gap: 6 }}>
              {holidays.map((h) => (
                <li key={h.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '6px 10px', background: 'var(--paper-2)', borderRadius: 6, fontSize: 13 }}>
                  <span><b>{h.date}</b>{h.isRecurring ? ' (каждый год)' : ''} — {h.label}</span>
                  <button className="kb-btn" style={{ fontSize: 11, padding: '2px 8px', background: '#dc2626', color: '#fff' }} onClick={() => void handleDeleteHoliday(h.id)}>×</button>
                </li>
              ))}
            </ul>
          )}
        </section>

        {/* Генерация */}
        <section className="kb-card" style={{ padding: 24, background: 'var(--violet-soft, #f3f0ff)' }}>
          <h2 style={{ margin: '0 0 12px', fontSize: 18, fontWeight: 800 }}>Сгенерировать слоты</h2>
          <p style={{ margin: '0 0 16px', fontSize: 13, color: 'var(--ink-soft)' }}>
            Создаст scheduled-слоты по правилам выше за указанный период. Идемпотентно: повторный запуск не задвоит.
          </p>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))', gap: 10, alignItems: 'end' }}>
            <div><label style={lbl}>С</label><input style={inp} type="date" value={genFrom} onChange={(e) => setGenFrom(e.target.value)} /></div>
            <div><label style={lbl}>По</label><input style={inp} type="date" value={genTo} onChange={(e) => setGenTo(e.target.value)} /></div>
            <button className="kb-btn" style={{ background: 'var(--violet)', color: '#fff' }} onClick={() => void handleGenerate()} disabled={generating}>
              {generating ? '…' : '⚡ Сгенерировать'}
            </button>
          </div>
        </section>
      </div>
    </PlatformShell>
  )
}

const lbl: React.CSSProperties = { display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: 'uppercase', color: 'var(--ink-soft)', marginBottom: 4 }
const inp: React.CSSProperties = { width: '100%', padding: '8px 10px', borderRadius: 8, border: '1px solid var(--paper-3)', fontSize: 13, fontFamily: 'inherit', boxSizing: 'border-box' }
